 7	import MigrationPolicyDetailsSection from './components/MigrationPolicyDetailsSection/MigrationPolicyDetailsSection';
 8	
 9	import './MigrationPolicyDetailsPage.scss';
10	
11	type MigrationPolicyDetailsPageProps = {
12	  obj: V1alpha1MigrationPolicy;
13	};
14	
15	const MigrationPolicyDetailsPage: FC<MigrationPolicyDetailsPageProps> = ({ obj: mp }) => {
